package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class GsonNewBuilderTest {

  @Test
  void testNewBuilderReturnsNonNullGsonBuilder() {
    Gson gson = new Gson();
    GsonBuilder builder = gson.newBuilder();
    assertNotNull(builder);
    assertEquals(gson, getGsonFieldFromBuilder(builder));
  }

  // Use reflection to access the private 'gson' field inside GsonBuilder
  private Gson getGsonFieldFromBuilder(GsonBuilder builder) {
    try {
      java.lang.reflect.Field gsonField = GsonBuilder.class.getDeclaredField("gson");
      gsonField.setAccessible(true);
      return (Gson) gsonField.get(builder);
    } catch (NoSuchFieldException | IllegalAccessException e) {
      fail("Reflection failed to access gson field in GsonBuilder");
      return null;
    }
  }
}
